import{_ as e,o as l,c as d,ae as a}from"./chunks/framework.BEtfQoF7.js";const f=JSON.parse('{"title":"인터랙티브 모드","description":"Claude Code 세션의 키보드 단축키, 입력 모드, 인터랙티브 기능에 대한 완전한 참조입니다.","frontmatter":{"title":"인터랙티브 모드","description":"Claude Code 세션의 키보드 단축키, 입력 모드, 인터랙티브 기능에 대한 완전한 참조입니다."},"headers":[],"relativePath":"interactive-mode.md","filePath":"interactive-mode.md","lastUpdated":1776205703000}'),o={name:"interactive-mode.md"};function i(s,t,c,n,r,h){return l(),d("div",null,[...t[0]||(t[0]=[a('<h1 id="인터랙티브-모드" tabindex="-1">인터랙티브 모드 <a class="header-anchor" href="#인터랙티브-모드" aria-label="Permalink to &quot;인터랙티브 모드&quot;">​</a></h1><h2 id="키보드-단축키" tabindex="-1">키보드 단축키 <a class="header-anchor" href="#키보드-단축키" aria-label="Permalink to &quot;키보드 단축키&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">참고</p><p>키보드 단축키는 플랫폼과 터미널에 따라 다를 수 있습니다. <code>?</code>를 눌러 현재 환경에서 사용 가능한 단축키를 확인하세요.</p><p><strong>macOS 사용자</strong>: Option/Alt 키 단축키(<code>Alt+B</code>, <code>Alt+F</code>, <code>Alt+Y</code>, <code>Alt+M</code>, <code>Alt+P</code>, <code>Alt+T</code>)는 터미널에서 Option을 Meta로 설정해야 합니다:</p><ul><li><strong>iTerm2</strong>: 설정 → Profiles → Keys → Left/Right Option key를 &quot;Esc+&quot;로 설정</li><li><strong>Terminal.app</strong>: 설정 → Profiles → Keyboard → &quot;Use Option as Meta Key&quot; 체크</li><li><strong>VS Code</strong>: VS Code 설정에서 <code>&quot;terminal.integrated.macOptionIsMeta&quot;: true</code> 설정</li></ul><p>자세한 내용은 <a href="/claude-code-docs-ko/terminal-config.html">터미널 설정</a>을 참조하세요.</p></div><h3 id="일반-컨트롤" tabindex="-1">일반 컨트롤 <a class="header-anchor" href="#일반-컨트롤" aria-label="Permalink to &quot;일반 컨트롤&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">단축키</th><th style="text-align:left;">설명</th><th style="text-align:left;">컨텍스트</th></tr></thead><tbody><tr><td style="text-align:left;"><code>Ctrl+C</code></td><td style="text-align:left;">현재 입력 또는 생성 취소</td><td style="text-align:left;">표준 인터럽트</td></tr><tr><td style="text-align:left;"><code>Ctrl+X Ctrl+K</code></td><td style="text-align:left;">모든 백그라운드 에이전트 종료. 3초 내에 두 번 눌러 확인</td><td style="text-align:left;">백그라운드 에이전트 제어</td></tr><tr><td style="text-align:left;"><code>Ctrl+D</code></td><td style="text-align:left;">Claude Code 세션 종료</td><td style="text-align:left;">EOF 시그널</td></tr><tr><td style="text-align:left;"><code>Ctrl+G</code> 또는 <code>Ctrl+X Ctrl+E</code></td><td style="text-align:left;">기본 텍스트 편집기에서 열기</td><td style="text-align:left;">기본 텍스트 편집기에서 프롬프트 또는 커스텀 응답을 편집합니다. <code>Ctrl+X Ctrl+E</code>는 readline 네이티브 바인딩입니다</td></tr><tr><td style="text-align:left;"><code>Ctrl+L</code></td><td style="text-align:left;">프롬프트 입력 지우기</td><td style="text-align:left;">입력한 텍스트를 지우고 대화 기록은 유지합니다</td></tr><tr><td style="text-align:left;"><code>Ctrl+O</code></td><td style="text-align:left;">트랜스크립트 뷰어 토글</td><td style="text-align:left;">상세한 도구 사용 및 실행을 표시합니다. 기본적으로 &quot;Called slack 3 times&quot;처럼 한 줄로 축약되는 MCP 호출도 확장합니다. <a href="/claude-code-docs-ko/fullscreen.html">전체 화면 렌더링</a>에서는 일반 프롬프트, 트랜스크립트 모드, 포커스 뷰(마지막 프롬프트 + 도구 요약 + 응답) 세 가지 상태를 순환합니다</td></tr><tr><td style="text-align:left;"><code>Ctrl+R</code></td><td style="text-align:left;">역방향 명령 기록 검색</td><td style="text-align:left;">이전 명령을 인터랙티브하게 검색합니다</td></tr><tr><td style="text-align:left;"><code>Ctrl+V</code> 또는 <code>Cmd+V</code> (iTerm2) 또는 <code>Alt+V</code> (Windows)</td><td style="text-align:left;">클립보드에서 이미지 붙여넣기</td><td style="text-align:left;">커서 위치에 <code>[Image #N]</code> 칩을 삽입하여 프롬프트에서 위치적으로 참조할 수 있습니다</td></tr><tr><td style="text-align:left;"><code>Ctrl+B</code></td><td style="text-align:left;">실행 중인 작업을 백그라운드로</td><td style="text-align:left;">bash 명령과 에이전트를 백그라운드로 전환합니다. Tmux 사용자는 두 번 누르세요</td></tr><tr><td style="text-align:left;"><code>Ctrl+T</code></td><td style="text-align:left;">작업 목록 토글</td><td style="text-align:left;">터미널 상태 영역에서 <a href="#작업-목록">작업 목록</a>을 표시하거나 숨깁니다</td></tr><tr><td style="text-align:left;"><code>Left/Right 화살표</code></td><td style="text-align:left;">대화 상자 탭 순환</td><td style="text-align:left;">권한 대화 상자와 메뉴에서 탭 간 이동</td></tr><tr><td style="text-align:left;"><code>Up/Down 화살표</code></td><td style="text-align:left;">명령 기록 탐색</td><td style="text-align:left;">이전 입력을 불러옵니다</td></tr><tr><td style="text-align:left;"><code>Esc</code> + <code>Esc</code></td><td style="text-align:left;">되감기 또는 요약</td><td style="text-align:left;">코드 및/또는 대화를 이전 지점으로 복원하거나 선택한 메시지부터 요약합니다</td></tr><tr><td style="text-align:left;"><code>Shift+Tab</code> 또는 <code>Alt+M</code> (일부 설정)</td><td style="text-align:left;">권한 모드 순환</td><td style="text-align:left;"><code>default</code>, <code>acceptEdits</code>, <code>plan</code> 및 <code>auto</code> 또는 <code>bypassPermissions</code> 같이 활성화한 모드를 순환합니다. <a href="/claude-code-docs-ko/permission-modes.html">권한 모드</a>를 참조하세요.</td></tr><tr><td style="text-align:left;"><code>Option+P</code> (macOS) 또는 <code>Alt+P</code> (Windows/Linux)</td><td style="text-align:left;">모델 전환</td><td style="text-align:left;">프롬프트를 지우지 않고 모델을 전환합니다</td></tr><tr><td style="text-align:left;"><code>Option+T</code> (macOS) 또는 <code>Alt+T</code> (Windows/Linux)</td><td style="text-align:left;">확장 사고 토글</td><td style="text-align:left;">확장 사고 모드를 활성화하거나 비활성화합니다. macOS에서는 이 단축키가 작동하도록 터미널에서 Option을 Meta로 전송하도록 설정하세요</td></tr><tr><td style="text-align:left;"><code>Option+O</code> (macOS) 또는 <code>Alt+O</code> (Windows/Linux)</td><td style="text-align:left;">빠른 모드 토글</td><td style="text-align:left;"><a href="/claude-code-docs-ko/fast-mode.html">빠른 모드</a>를 활성화하거나 비활성화합니다</td></tr></tbody></table><h3 id="텍스트-편집" tabindex="-1">텍스트 편집 <a class="header-anchor" href="#텍스트-편집" aria-label="Permalink to &quot;텍스트 편집&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">단축키</th><th style="text-align:left;">설명</th><th style="text-align:left;">컨텍스트</th></tr></thead><tbody><tr><td style="text-align:left;"><code>Ctrl+K</code></td><td style="text-align:left;">줄 끝까지 삭제</td><td style="text-align:left;">삭제된 텍스트를 붙여넣기용으로 저장합니다</td></tr><tr><td style="text-align:left;"><code>Ctrl+U</code></td><td style="text-align:left;">커서에서 줄 시작까지 삭제</td><td style="text-align:left;">삭제된 텍스트를 붙여넣기용으로 저장합니다. 여러 줄 입력에서 반복하면 줄을 넘어 지웁니다</td></tr><tr><td style="text-align:left;"><code>Ctrl+Y</code></td><td style="text-align:left;">삭제된 텍스트 붙여넣기</td><td style="text-align:left;"><code>Ctrl+K</code> 또는 <code>Ctrl+U</code>로 삭제한 텍스트를 붙여넣습니다</td></tr><tr><td style="text-align:left;"><code>Alt+Y</code> (<code>Ctrl+Y</code> 후)</td><td style="text-align:left;">붙여넣기 기록 순환</td><td style="text-align:left;">붙여넣기 후 이전에 삭제한 텍스트를 순환합니다. macOS에서는 <a href="#키보드-단축키">Option을 Meta로</a> 설정해야 합니다</td></tr><tr><td style="text-align:left;"><code>Alt+B</code></td><td style="text-align:left;">커서를 한 단어 뒤로 이동</td><td style="text-align:left;">단어 탐색. macOS에서는 <a href="#키보드-단축키">Option을 Meta로</a> 설정해야 합니다</td></tr><tr><td style="text-align:left;"><code>Alt+F</code></td><td style="text-align:left;">커서를 한 단어 앞으로 이동</td><td style="text-align:left;">단어 탐색. macOS에서는 <a href="#키보드-단축키">Option을 Meta로</a> 설정해야 합니다</td></tr></tbody></table><h3 id="테마-및-디스플레이" tabindex="-1">테마 및 디스플레이 <a class="header-anchor" href="#테마-및-디스플레이" aria-label="Permalink to &quot;테마 및 디스플레이&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">단축키</th><th style="text-align:left;">설명</th><th style="text-align:left;">컨텍스트</th></tr></thead><tbody><tr><td style="text-align:left;"><code>Ctrl+T</code></td><td style="text-align:left;">코드 블록의 구문 강조 토글</td><td style="text-align:left;"><code>/theme</code> 선택 메뉴 내에서만 작동합니다. Claude 응답의 코드에 구문 색상을 사용할지 제어합니다</td></tr></tbody></table><h3 id="여러-줄-입력" tabindex="-1">여러 줄 입력 <a class="header-anchor" href="#여러-줄-입력" aria-label="Permalink to &quot;여러 줄 입력&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">방법</th><th style="text-align:left;">단축키</th><th style="text-align:left;">컨텍스트</th></tr></thead><tbody><tr><td style="text-align:left;">빠른 이스케이프</td><td style="text-align:left;"><code>\\</code> + <code>Enter</code></td><td style="text-align:left;">모든 터미널에서 작동합니다</td></tr><tr><td style="text-align:left;">macOS 기본</td><td style="text-align:left;"><code>Option+Enter</code></td><td style="text-align:left;">macOS 기본값</td></tr><tr><td style="text-align:left;">Shift+Enter</td><td style="text-align:left;"><code>Shift+Enter</code></td><td style="text-align:left;">iTerm2, WezTerm, Ghostty, Kitty에서 바로 작동합니다</td></tr><tr><td style="text-align:left;">제어 시퀀스</td><td style="text-align:left;"><code>Ctrl+J</code></td><td style="text-align:left;">여러 줄 입력을 위한 줄 바꿈 문자</td></tr><tr><td style="text-align:left;">붙여넣기 모드</td><td style="text-align:left;">직접 붙여넣기</td><td style="text-align:left;">코드 블록, 로그용</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Shift+Enter는 iTerm2, WezTerm, Ghostty, Kitty에서 설정 없이 작동합니다. 다른 터미널(VS Code, Alacritty, Zed, Warp)의 경우 <code>/terminal-setup</code>을 실행하여 바인딩을 설치하세요.</p></div><h3 id="빠른-명령" tabindex="-1">빠른 명령 <a class="header-anchor" href="#빠른-명령" aria-label="Permalink to &quot;빠른 명령&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">단축키</th><th style="text-align:left;">설명</th><th style="text-align:left;">참고</th></tr></thead><tbody><tr><td style="text-align:left;"><code>/</code> (시작 부분)</td><td style="text-align:left;">명령 또는 스킬</td><td style="text-align:left;"><a href="#명령">명령</a> 및 <a href="/claude-code-docs-ko/skills.html">스킬</a>을 참조하세요</td></tr><tr><td style="text-align:left;"><code>!</code> (시작 부분)</td><td style="text-align:left;">Bash 모드</td><td style="text-align:left;">명령을 직접 실행하고 실행 출력을 세션에 추가합니다</td></tr><tr><td style="text-align:left;"><code>@</code></td><td style="text-align:left;">파일 경로 멘션</td><td style="text-align:left;">파일 경로 자동 완성을 트리거합니다</td></tr></tbody></table><h3 id="트랜스크립트-뷰어" tabindex="-1">트랜스크립트 뷰어 <a class="header-anchor" href="#트랜스크립트-뷰어" aria-label="Permalink to &quot;트랜스크립트 뷰어&quot;">​</a></h3><p>트랜스크립트 뷰어가 열려 있을 때(<code>Ctrl+O</code>로 토글), 다음 단축키를 사용할 수 있습니다. <code>Ctrl+E</code>는 <a href="/claude-code-docs-ko/keybindings.html"><code>transcript:toggleShowAll</code></a>을 통해 다시 바인딩할 수 있습니다.</p><table tabindex="0"><thead><tr><th style="text-align:left;">단축키</th><th style="text-align:left;">설명</th></tr></thead><tbody><tr><td style="text-align:left;"><code>Ctrl+E</code></td><td style="text-align:left;">모든 콘텐츠 표시 토글</td></tr><tr><td style="text-align:left;"><code>q</code>, <code>Ctrl+C</code>, <code>Esc</code></td><td style="text-align:left;">트랜스크립트 뷰 종료. 세 가지 모두 <a href="/claude-code-docs-ko/keybindings.html"><code>transcript:exit</code></a>를 통해 다시 바인딩할 수 있습니다</td></tr></tbody></table><h3 id="음성-입력" tabindex="-1">음성 입력 <a class="header-anchor" href="#음성-입력" aria-label="Permalink to &quot;음성 입력&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">단축키</th><th style="text-align:left;">설명</th><th style="text-align:left;">참고</th></tr></thead><tbody><tr><td style="text-align:left;"><code>Space</code> 길게 누르기</td><td style="text-align:left;">푸시 투 톡 받아쓰기</td><td style="text-align:left;"><a href="/claude-code-docs-ko/voice-dictation.html">음성 받아쓰기</a>가 활성화되어 있어야 합니다. 트랜스크립트가 커서 위치에 삽입됩니다. <a href="/claude-code-docs-ko/voice-dictation.html#rebind-the-push-to-talk-key">다시 바인딩 가능</a></td></tr></tbody></table><h2 id="명령" tabindex="-1">명령 <a class="header-anchor" href="#명령" aria-label="Permalink to &quot;명령&quot;">​</a></h2><p>Claude Code에서 <code>/</code>를 입력하면 사용 가능한 모든 명령을 볼 수 있고, <code>/</code> 다음에 아무 글자나 입력하면 필터링할 수 있습니다. <code>/</code> 메뉴는 호출할 수 있는 모든 것을 표시합니다: 내장 명령, 번들 및 사용자 작성 <a href="/claude-code-docs-ko/skills.html">스킬</a>, <a href="/claude-code-docs-ko/plugins.html">플러그인</a> 및 <a href="/claude-code-docs-ko/mcp.html#use-mcp-prompts-as-commands">MCP 서버</a>가 제공하는 명령. 일부 내장 명령은 플랫폼이나 플랜에 따라 모든 사용자에게 표시되지 않을 수 있습니다.</p><p>Claude Code에 포함된 전체 명령 목록은 <a href="/claude-code-docs-ko/commands.html">명령 참조</a>를 확인하세요.</p><h2 id="vim-편집기-모드" tabindex="-1">Vim 편집기 모드 <a class="header-anchor" href="#vim-편집기-모드" aria-label="Permalink to &quot;Vim 편집기 모드&quot;">​</a></h2><p><code>/config</code> → Editor mode를 통해 vim 스타일 편집을 활성화하세요.</p><h3 id="모드-전환" tabindex="-1">모드 전환 <a class="header-anchor" href="#모드-전환" aria-label="Permalink to &quot;모드 전환&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">명령</th><th style="text-align:left;">동작</th><th style="text-align:left;">소스 모드</th></tr></thead><tbody><tr><td style="text-align:left;"><code>Esc</code></td><td style="text-align:left;">NORMAL 모드 진입</td><td style="text-align:left;">INSERT</td></tr><tr><td style="text-align:left;"><code>i</code></td><td style="text-align:left;">커서 앞에 삽입</td><td style="text-align:left;">NORMAL</td></tr><tr><td style="text-align:left;"><code>I</code></td><td style="text-align:left;">줄 시작에 삽입</td><td style="text-align:left;">NORMAL</td></tr><tr><td style="text-align:left;"><code>a</code></td><td style="text-align:left;">커서 뒤에 삽입</td><td style="text-align:left;">NORMAL</td></tr><tr><td style="text-align:left;"><code>A</code></td><td style="text-align:left;">줄 끝에 삽입</td><td style="text-align:left;">NORMAL</td></tr><tr><td style="text-align:left;"><code>o</code></td><td style="text-align:left;">아래에 새 줄 열기</td><td style="text-align:left;">NORMAL</td></tr><tr><td style="text-align:left;"><code>O</code></td><td style="text-align:left;">위에 새 줄 열기</td><td style="text-align:left;">NORMAL</td></tr></tbody></table><h3 id="탐색-normal-모드" tabindex="-1">탐색 (NORMAL 모드) <a class="header-anchor" href="#탐색-normal-모드" aria-label="Permalink to &quot;탐색 (NORMAL 모드)&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">명령</th><th style="text-align:left;">동작</th></tr></thead><tbody><tr><td style="text-align:left;"><code>h</code>/<code>j</code>/<code>k</code>/<code>l</code></td><td style="text-align:left;">왼쪽/아래/위/오른쪽 이동</td></tr><tr><td style="text-align:left;"><code>w</code></td><td style="text-align:left;">다음 단어</td></tr><tr><td style="text-align:left;"><code>e</code></td><td style="text-align:left;">단어 끝</td></tr><tr><td style="text-align:left;"><code>b</code></td><td style="text-align:left;">이전 단어</td></tr><tr><td style="text-align:left;"><code>0</code></td><td style="text-align:left;">줄 시작</td></tr><tr><td style="text-align:left;"><code>$</code></td><td style="text-align:left;">줄 끝</td></tr><tr><td style="text-align:left;"><code>^</code></td><td style="text-align:left;">첫 번째 비공백 문자</td></tr><tr><td style="text-align:left;"><code>gg</code></td><td style="text-align:left;">입력 시작</td></tr><tr><td style="text-align:left;"><code>G</code></td><td style="text-align:left;">입력 끝</td></tr><tr><td style="text-align:left;"><code>f{char}</code></td><td style="text-align:left;">다음 문자 발생 위치로 점프</td></tr><tr><td style="text-align:left;"><code>F{char}</code></td><td style="text-align:left;">이전 문자 발생 위치로 점프</td></tr><tr><td style="text-align:left;"><code>t{char}</code></td><td style="text-align:left;">다음 문자 발생 직전으로 점프</td></tr><tr><td style="text-align:left;"><code>T{char}</code></td><td style="text-align:left;">이전 문자 발생 직후로 점프</td></tr><tr><td style="text-align:left;"><code>;</code></td><td style="text-align:left;">마지막 f/F/t/T 모션 반복</td></tr><tr><td style="text-align:left;"><code>,</code></td><td style="text-align:left;">마지막 f/F/t/T 모션 역방향 반복</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">참고</p><p>vim normal 모드에서 커서가 입력의 시작 또는 끝에 있어 더 이상 이동할 수 없을 때, <code>j</code>/<code>k</code> 및 화살표 키는 대신 명령 기록을 탐색합니다.</p></div><h3 id="편집-normal-모드" tabindex="-1">편집 (NORMAL 모드) <a class="header-anchor" href="#편집-normal-모드" aria-label="Permalink to &quot;편집 (NORMAL 모드)&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">명령</th><th style="text-align:left;">동작</th></tr></thead><tbody><tr><td style="text-align:left;"><code>x</code></td><td style="text-align:left;">문자 삭제</td></tr><tr><td style="text-align:left;"><code>dd</code></td><td style="text-align:left;">줄 삭제</td></tr><tr><td style="text-align:left;"><code>D</code></td><td style="text-align:left;">줄 끝까지 삭제</td></tr><tr><td style="text-align:left;"><code>dw</code>/<code>de</code>/<code>db</code></td><td style="text-align:left;">단어/끝까지/뒤로 삭제</td></tr><tr><td style="text-align:left;"><code>cc</code></td><td style="text-align:left;">줄 변경</td></tr><tr><td style="text-align:left;"><code>C</code></td><td style="text-align:left;">줄 끝까지 변경</td></tr><tr><td style="text-align:left;"><code>cw</code>/<code>ce</code>/<code>cb</code></td><td style="text-align:left;">단어/끝까지/뒤로 변경</td></tr><tr><td style="text-align:left;"><code>yy</code>/<code>Y</code></td><td style="text-align:left;">줄 복사(yank)</td></tr><tr><td style="text-align:left;"><code>yw</code>/<code>ye</code>/<code>yb</code></td><td style="text-align:left;">단어/끝까지/뒤로 복사</td></tr><tr><td style="text-align:left;"><code>p</code></td><td style="text-align:left;">커서 뒤에 붙여넣기</td></tr><tr><td style="text-align:left;"><code>P</code></td><td style="text-align:left;">커서 앞에 붙여넣기</td></tr><tr><td style="text-align:left;"><code>&gt;&gt;</code></td><td style="text-align:left;">줄 들여쓰기</td></tr><tr><td style="text-align:left;"><code>&lt;&lt;</code></td><td style="text-align:left;">줄 내어쓰기</td></tr><tr><td style="text-align:left;"><code>J</code></td><td style="text-align:left;">줄 합치기</td></tr><tr><td style="text-align:left;"><code>.</code></td><td style="text-align:left;">마지막 변경 반복</td></tr></tbody></table><h3 id="텍스트-객체-normal-모드" tabindex="-1">텍스트 객체 (NORMAL 모드) <a class="header-anchor" href="#텍스트-객체-normal-모드" aria-label="Permalink to &quot;텍스트 객체 (NORMAL 모드)&quot;">​</a></h3><p>텍스트 객체는 <code>d</code>, <code>c</code>, <code>y</code> 같은 연산자와 함께 작동합니다:</p><table tabindex="0"><thead><tr><th style="text-align:left;">명령</th><th style="text-align:left;">동작</th></tr></thead><tbody><tr><td style="text-align:left;"><code>iw</code>/<code>aw</code></td><td style="text-align:left;">단어 내부/주변</td></tr><tr><td style="text-align:left;"><code>iW</code>/<code>aW</code></td><td style="text-align:left;">WORD(공백 구분) 내부/주변</td></tr><tr><td style="text-align:left;"><code>i&quot;</code>/<code>a&quot;</code></td><td style="text-align:left;">큰따옴표 내부/주변</td></tr><tr><td style="text-align:left;"><code>i&#39;</code>/<code>a&#39;</code></td><td style="text-align:left;">작은따옴표 내부/주변</td></tr><tr><td style="text-align:left;"><code>i(</code>/<code>a(</code></td><td style="text-align:left;">괄호 내부/주변</td></tr><tr><td style="text-align:left;"><code>i[</code>/<code>a[</code></td><td style="text-align:left;">대괄호 내부/주변</td></tr><tr><td style="text-align:left;"><code>i{</code>/<code>a{</code></td><td style="text-align:left;">중괄호 내부/주변</td></tr></tbody></table><h2 id="명령-기록" tabindex="-1">명령 기록 <a class="header-anchor" href="#명령-기록" aria-label="Permalink to &quot;명령 기록&quot;">​</a></h2><p>Claude Code는 현재 세션의 명령 기록을 유지합니다:</p><ul><li>입력 기록은 작업 디렉토리별로 저장됩니다</li><li><code>/clear</code>를 실행하여 새 세션을 시작하면 입력 기록이 초기화됩니다. 이전 세션의 대화는 보존되며 다시 시작할 수 있습니다.</li><li>Up/Down 화살표로 탐색합니다 (위의 키보드 단축키 참조)</li><li><strong>참고</strong>: 기록 확장(<code>!</code>)은 기본적으로 비활성화되어 있습니다</li></ul><h3 id="ctrl-r로-역방향-검색" tabindex="-1">Ctrl+R로 역방향 검색 <a class="header-anchor" href="#ctrl-r로-역방향-검색" aria-label="Permalink to &quot;Ctrl+R로 역방향 검색&quot;">​</a></h3><p><code>Ctrl+R</code>을 눌러 명령 기록을 인터랙티브하게 검색합니다:</p><ol><li><strong>검색 시작</strong>: <code>Ctrl+R</code>을 눌러 역방향 기록 검색을 활성화합니다</li><li><strong>쿼리 입력</strong>: 이전 명령에서 검색할 텍스트를 입력합니다. 검색어가 일치하는 결과에서 강조 표시됩니다</li><li><strong>일치 항목 탐색</strong>: <code>Ctrl+R</code>을 다시 눌러 이전 일치 항목을 순환합니다</li><li><strong>일치 항목 수락</strong>: <ul><li><code>Tab</code> 또는 <code>Esc</code>를 눌러 현재 일치 항목을 수락하고 계속 편집합니다</li><li><code>Enter</code>를 눌러 수락하고 즉시 명령을 실행합니다</li></ul></li><li><strong>검색 취소</strong>: <ul><li><code>Ctrl+C</code>를 눌러 취소하고 원래 입력을 복원합니다</li><li>빈 검색에서 <code>Backspace</code>를 눌러 취소합니다</li></ul></li></ol><p>검색은 검색어가 강조 표시된 일치하는 명령을 표시하여 이전 입력을 찾고 재사용할 수 있게 합니다.</p><h2 id="백그라운드-bash-명령" tabindex="-1">백그라운드 bash 명령 <a class="header-anchor" href="#백그라운드-bash-명령" aria-label="Permalink to &quot;백그라운드 bash 명령&quot;">​</a></h2><p>Claude Code는 백그라운드에서 bash 명령 실행을 지원하여, 장시간 실행되는 프로세스가 실행되는 동안 계속 작업할 수 있습니다.</p><h3 id="백그라운드-작동-방식" tabindex="-1">백그라운드 작동 방식 <a class="header-anchor" href="#백그라운드-작동-방식" aria-label="Permalink to &quot;백그라운드 작동 방식&quot;">​</a></h3><p>Claude Code가 백그라운드에서 명령을 실행하면, 비동기적으로 명령을 실행하고 즉시 백그라운드 작업 ID를 반환합니다. 명령이 백그라운드에서 계속 실행되는 동안 Claude Code는 새 프롬프트에 응답할 수 있습니다.</p><p>백그라운드에서 명령을 실행하려면 다음 중 하나를 수행할 수 있습니다:</p><ul><li>Claude Code에 명령을 백그라운드에서 실행하도록 프롬프트합니다</li><li>Ctrl+B를 눌러 일반 Bash 도구 호출을 백그라운드로 이동합니다. (Tmux 사용자는 tmux의 프리픽스 키 때문에 Ctrl+B를 두 번 눌러야 합니다.)</li></ul><p><strong>주요 기능:</strong></p><ul><li>출력은 파일에 기록되며 Claude가 Read 도구를 사용하여 검색할 수 있습니다</li><li>백그라운드 작업에는 추적 및 출력 검색을 위한 고유 ID가 있습니다</li><li>Claude Code가 종료되면 백그라운드 작업이 자동으로 정리됩니다</li><li>출력이 5GB를 초과하면 백그라운드 작업이 자동으로 종료되며, 이유를 설명하는 메모가 stderr에 기록됩니다</li></ul><p>모든 백그라운드 작업 기능을 비활성화하려면 <code>CLAUDE_CODE_DISABLE_BACKGROUND_TASKS</code> 환경 변수를 <code>1</code>로 설정하세요. 자세한 내용은 <a href="/claude-code-docs-ko/env-vars.html">환경 변수</a>를 참조하세요.</p><p><strong>일반적으로 백그라운드로 실행하는 명령:</strong></p><ul><li>빌드 도구 (webpack, vite, make)</li><li>패키지 관리자 (npm, yarn, pnpm)</li><li>테스트 러너 (jest, pytest)</li><li>개발 서버</li><li>장시간 실행 프로세스 (docker, terraform)</li></ul><h3 id="접두사를-사용한-bash-모드" tabindex="-1"><code>!</code> 접두사를 사용한 Bash 모드 <a class="header-anchor" href="#접두사를-사용한-bash-모드" aria-label="Permalink to &quot;`!` 접두사를 사용한 Bash 모드&quot;">​</a></h3><p>입력 앞에 <code>!</code>를 붙여 Claude를 거치지 않고 직접 bash 명령을 실행합니다:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">!</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">!</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">!</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> ls</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -la</span></span></code></pre></div><p>Bash 모드:</p><ul><li>명령과 출력을 대화 컨텍스트에 추가합니다</li><li>실시간 진행 상황과 출력을 표시합니다</li><li>장시간 실행 명령에 동일한 <code>Ctrl+B</code> 백그라운드 전환을 지원합니다</li><li>Claude가 명령을 해석하거나 승인할 필요가 없습니다</li><li>기록 기반 자동 완성을 지원합니다: 부분 명령을 입력하고 <strong>Tab</strong>을 눌러 현재 프로젝트의 이전 <code>!</code> 명령에서 완성합니다</li><li>빈 프롬프트에서 <code>Escape</code>, <code>Backspace</code> 또는 <code>Ctrl+U</code>로 종료합니다</li><li><code>!</code>로 시작하는 텍스트를 빈 프롬프트에 붙여넣으면 자동으로 bash 모드로 진입하여, 입력한 <code>!</code> 동작과 일치합니다</li></ul><p>대화 컨텍스트를 유지하면서 빠른 셸 작업에 유용합니다.</p><h2 id="프롬프트-제안" tabindex="-1">프롬프트 제안 <a class="header-anchor" href="#프롬프트-제안" aria-label="Permalink to &quot;프롬프트 제안&quot;">​</a></h2><p>세션을 처음 열면, 시작을 돕기 위해 프롬프트 입력에 회색으로 된 예시 명령이 나타납니다. Claude Code는 프로젝트의 git 기록에서 이를 선택하여, 최근 작업한 파일을 반영합니다.</p><p>Claude가 응답한 후에도, 여러 부분 요청의 후속 단계나 워크플로의 자연스러운 연속 같은 대화 기록에 기반한 제안이 계속 나타납니다.</p><ul><li><strong>Tab</strong> 또는 <strong>오른쪽 화살표</strong>를 눌러 제안을 수락하거나, <strong>Enter</strong>를 눌러 수락하고 제출합니다</li><li>입력을 시작하면 제안이 사라집니다</li></ul><p>제안은 상위 대화의 프롬프트 캐시를 재사용하는 백그라운드 요청으로 실행되므로, 추가 비용이 최소화됩니다. Claude Code는 불필요한 비용을 피하기 위해 캐시가 콜드 상태일 때 제안 생성을 건너뜁니다.</p><p>대화의 첫 번째 턴 후, 비인터랙티브 모드, plan 모드에서는 제안이 자동으로 건너뛰어집니다.</p><p>프롬프트 제안을 완전히 비활성화하려면 환경 변수를 설정하거나 <code>/config</code>에서 설정을 토글하세요:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> CLAUDE_CODE_ENABLE_PROMPT_SUGGESTION</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">false</span></span></code></pre></div><h2 id="btw로-사이드-질문" tabindex="-1">/btw로 사이드 질문 <a class="header-anchor" href="#btw로-사이드-질문" aria-label="Permalink to &quot;/btw로 사이드 질문&quot;">​</a></h2><p><code>/btw</code>를 사용하여 대화 기록에 추가하지 않고 현재 작업에 대해 빠른 질문을 할 수 있습니다. 빠른 답변이 필요하지만 메인 컨텍스트를 어지럽히거나 Claude가 장시간 실행 중인 작업에서 벗어나는 것을 원하지 않을 때 유용합니다.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/btw what was the name of that config file again?</span></span></code></pre></div><p>사이드 질문은 현재 대화에 대한 전체 가시성을 가지므로, Claude가 이미 읽은 코드, 이전에 내린 결정, 또는 세션의 다른 모든 것에 대해 질문할 수 있습니다. 질문과 답변은 일시적입니다: 닫을 수 있는 오버레이에 나타나며 대화 기록에 절대 들어가지 않습니다.</p><ul><li><strong>Claude가 작업 중일 때 사용 가능</strong>: Claude가 응답을 처리하는 동안에도 <code>/btw</code>를 실행할 수 있습니다. 사이드 질문은 독립적으로 실행되며 메인 턴을 중단하지 않습니다.</li><li><strong>도구 접근 없음</strong>: 사이드 질문은 이미 컨텍스트에 있는 것에서만 답변합니다. Claude는 사이드 질문에 답변할 때 파일을 읽거나, 명령을 실행하거나, 검색할 수 없습니다.</li><li><strong>단일 응답</strong>: 후속 턴이 없습니다. 대화가 필요하면 일반 프롬프트를 대신 사용하세요.</li><li><strong>낮은 비용</strong>: 사이드 질문은 상위 대화의 프롬프트 캐시를 재사용하므로, 추가 비용이 최소화됩니다.</li></ul><p><strong>Space</strong>, <strong>Enter</strong> 또는 <strong>Escape</strong>를 눌러 답변을 닫고 프롬프트로 돌아갑니다.</p><p><code>/btw</code>는 <a href="/claude-code-docs-ko/sub-agents.html">서브에이전트</a>의 반대입니다: 전체 대화를 볼 수 있지만 도구가 없는 반면, 서브에이전트는 전체 도구를 가지지만 빈 컨텍스트로 시작합니다. 이 세션에서 Claude가 이미 알고 있는 것에 대해 질문하려면 <code>/btw</code>를 사용하고, 새로운 것을 찾으려면 서브에이전트를 사용하세요.</p><h2 id="작업-목록" tabindex="-1">작업 목록 <a class="header-anchor" href="#작업-목록" aria-label="Permalink to &quot;작업 목록&quot;">​</a></h2><p>복잡한 여러 단계의 작업을 수행할 때, Claude는 진행 상황을 추적하기 위한 작업 목록을 생성합니다. 작업은 대기 중, 진행 중, 완료를 나타내는 표시기와 함께 터미널의 상태 영역에 나타납니다.</p><ul><li><code>Ctrl+T</code>를 눌러 작업 목록 뷰를 토글합니다. 디스플레이는 한 번에 최대 10개의 작업을 표시합니다</li><li>모든 작업을 보거나 지우려면 Claude에게 직접 요청하세요: &quot;show me all tasks&quot; 또는 &quot;clear all tasks&quot;</li><li>작업은 컨텍스트 압축 후에도 유지되어, 더 큰 프로젝트에서 Claude가 체계적으로 유지되도록 돕습니다</li><li>세션 간에 작업 목록을 공유하려면 <code>CLAUDE_CODE_TASK_LIST_ID</code>를 설정하여 <code>~/.claude/tasks/</code>에 명명된 디렉토리를 사용합니다: <code>CLAUDE_CODE_TASK_LIST_ID=my-project claude</code></li></ul><h2 id="pr-리뷰-상태" tabindex="-1">PR 리뷰 상태 <a class="header-anchor" href="#pr-리뷰-상태" aria-label="Permalink to &quot;PR 리뷰 상태&quot;">​</a></h2><p>열린 풀 리퀘스트가 있는 브랜치에서 작업할 때, Claude Code는 푸터에 클릭 가능한 PR 링크(예: &quot;PR #446&quot;)를 표시합니다. 링크에는 리뷰 상태를 나타내는 색상 밑줄이 있습니다:</p><ul><li>녹색: 승인됨</li><li>노란색: 리뷰 대기 중</li><li>빨간색: 변경 요청됨</li><li>회색: 초안</li><li>보라색: 병합됨</li></ul><p><code>Cmd+클릭</code> (Mac) 또는 <code>Ctrl+클릭</code> (Windows/Linux)으로 링크를 클릭하여 브라우저에서 풀 리퀘스트를 엽니다. 상태는 60초마다 자동으로 업데이트됩니다.</p><div class="info custom-block"><p class="custom-block-title">참고</p><p>PR 상태를 사용하려면 <code>gh</code> CLI가 설치되고 인증(<code>gh auth login</code>)되어 있어야 합니다.</p></div><h2 id="참고-항목" tabindex="-1">참고 항목 <a class="header-anchor" href="#참고-항목" aria-label="Permalink to &quot;참고 항목&quot;">​</a></h2><ul><li><a href="/claude-code-docs-ko/skills.html">스킬</a> - 커스텀 프롬프트 및 워크플로</li><li><a href="/claude-code-docs-ko/checkpointing.html">체크포인팅</a> - Claude의 편집을 되감고 이전 상태를 복원</li><li><a href="/claude-code-docs-ko/cli-reference.html">CLI 참조</a> - 명령줄 플래그 및 옵션</li><li><a href="/claude-code-docs-ko/settings.html">설정</a> - 설정 옵션</li><li><a href="/claude-code-docs-ko/memory.html">메모리 관리</a> - CLAUDE.md 파일 관리</li></ul>',83)])])}const y=e(o,[["render",i]]);export{f as __pageData,y as default};
